const body = $input.first().json;

const userName = body.data?.user_name || 'Artist';
const userEmail = body.data?.user_email;
const streak = body.data?.practice_streak || 0;
const completedLessons = body.data?.completed_lessons || 0;
const totalLessons = body.data?.total_lessons || 0;
const suggested = body.data?.suggested_duration || 30;

if (!userEmail) {
  throw new Error('No user_email in event data');
}

const streakMsg = streak > 0
  ? `You're on a ${streak}-day streak — keep it going!`
  : 'Start a new streak today!';

const emailSubject = `🎨 Time for your daily art practice, ${userName}!`;

const emailBody = `Hi ${userName},

It's time for your daily art practice session!

${streakMsg}

Your progress so far: ${completedLessons} of ${totalLessons} lessons completed.

Recommended session: ${suggested} minutes of drawing practice and technique review.

Open Art Buddy and keep creating: https://art-buddy-frontend.onrender.com

Happy drawing!
The Art Buddy Team`;

return [{
  json: {
    user_email: userEmail,
    user_name: userName,
    emailSubject,
    emailBody
  }
}];
